INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('ffb383862373fbc7', 'NC', '["federal","state","county","municipal","judicial"]', 'runoff_rules', 'What percentage of the vote do I need to avoid a primary runoff in North Carolina?', '["NC primary runoff threshold","Do I need 50 percent to win the primary?","What triggers a second primary?"]', 'In North Carolina, a candidate must receive a ''substantial plurality'' to win a primary outright. Statute strictly defines this: the total votes cast for all candidates are multiplied by 30%, and the winning candidate''s vote must equal or exceed that multiple, plus one vote.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-111.html', 'N.C.G.S. § 163-111(a)(1)', '2026-05-10', 'static', 'statute_citation', 'Applies to all candidates in partisan primary elections.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('117d991f4d61ebe4', 'NC', '["federal","state","county","municipal","judicial"]', 'runoff_rules', 'If no one gets 30% in the primary, is a runoff scheduled automatically?', '["Does the second primary happen automatically?","How to trigger a runoff","Requesting a second primary"]', 'No. A second primary (runoff) is not automatic. If no candidate reaches the 30% threshold, the second-place candidate must officially request the second primary in writing to the State Board of Elections by 12:00 noon on the ninth day after the primary.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-111.html', 'N.C.G.S. § 163-111(c)(1)', '2026-05-10', 'static', 'statute_citation', 'Applies to the second-highest vote-getter in a primary where no one reaches 30%.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('58bc7fc07d8408fc', 'NC', '["federal","state","county","judicial"]', 'election_dates', 'When is the 2026 Primary Election in North Carolina?', '["NC primary date 2026","When do voters vote in the primary?","March primary date"]', 'The North Carolina primary election is held on the first Tuesday after the first Monday in March of even-numbered years. For the 2026 cycle, this is Tuesday, March 3, 2026.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-1.html', 'N.C.G.S. § 163-1(b)', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to all voters and candidates on the primary ballot.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('4accb108444ed1eb', 'NC', '["federal","state","county","judicial"]', 'election_dates', 'When is the 2026 Second Primary (Runoff) held if federal offices are involved?', '["Runoff date 2026","When is the second primary?","May runoff timing"]', 'Because federal offices (U.S. Senate, U.S. House) are on the 2026 ballot, state law requires any second primary to be held exactly 10 weeks after the first primary, making the 2026 runoff date Tuesday, May 12, 2026.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-111.html', 'N.C.G.S. § 163-111(e)', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to candidates competing in a second primary during federal election years.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('19fb36e69343db75', 'NC', '["state","county","judicial"]', 'election_dates', 'When is a Second Primary (Runoff) held if NO federal offices are on the ballot?', '["7 week runoff rule","Off-year runoff timing","When is the second primary in a purely state election?"]', 'In election cycles where no federal offices are involved in the second primary, North Carolina law mandates that the second primary be held exactly 7 weeks after the first primary (e.g., April 21, 2026, if applicable).', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-111.html', 'N.C.G.S. § 163-111(e)', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates competing in a second primary during non-federal cycles.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('0ea91053e5d79d2b', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'When is the 2026 General Election in North Carolina?', '["Election day 2026","What date is the November election?","Fall general election date"]', 'The 2026 General Election is scheduled for Tuesday, November 3, 2026.', 'https://www.ncsbe.gov/voting/upcoming-election', 'North Carolina State Board of Elections – Upcoming Election', '2026-05-10', 'per_cycle', 'official_source_direct', 'Applies to all voters and candidates in North Carolina.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('10b7896dbea93804', 'NC', '["federal","state","county","judicial"]', 'ballot_access', 'When is the candidate filing period for the 2026 elections?', '["When do I file for office?","December qualifying dates","Deadline to submit notice of candidacy"]', 'Candidate filing for the 2026 primary begins at 12:00 noon on Monday, December 1, 2025, and closes at 12:00 noon on Friday, December 19, 2025.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-106.2.html', 'N.C.G.S. § 163-106.2(a)', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to candidates seeking state, county, judicial, and federal office.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('2b4e83339d43ad89', 'NC', '["judicial"]', 'ballot_access', 'Do judicial candidates run with a party label in North Carolina?', '["Are judge races partisan?","Do judges have a D or R next to their name?","Partisan judicial elections"]', 'Yes. Since legislative changes fully took effect in 2018, all regular judicial elections in North Carolina (Supreme Court, Court of Appeals, Superior Court, and District Court) are partisan, meaning candidates run in party primaries and appear with party labels on the general election ballot.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-106.html', 'N.C.G.S. § 163-106', '2026-05-10', 'static', 'statute_citation', 'Applies to all candidates for judicial office.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('91a5398e9048481d', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can my campaign accept donations from a corporation or LLC?', '["Are corporate contributions legal?","Can a business write a campaign check?","Corporate donation ban"]', 'No. North Carolina law strictly prohibits corporations, business entities, and labor unions from making direct contributions to political candidates or candidate campaign committees.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-278.19.html', 'N.C.G.S. § 163-278.19(a)', '2026-05-10', 'static', 'statute_citation', 'Applies to all candidate campaign committees.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('860a2c22fdfb7d92', 'NC', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What is the maximum individual contribution limit for a candidate?', '["How much can one person donate?","Maximum campaign contribution cap","Individual donor limits"]', 'The base individual contribution limit is $6,400 per election (the primary and general count as separate elections). This exact dollar threshold is statutorily adjusted by the State Board of Elections in January of every odd-numbered year based on the Consumer Price Index.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-278.13.html', 'N.C.G.S. § 163-278.13(b)', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to state and local candidates and their donors.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('9125fd62ec73abe0', 'NC', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Are PAC contribution limits higher than individual limits?', '["How much can a PAC give?","Political committee donation caps","Do PACs have the same limits as people?"]', 'No. Standard Political Action Committees (PACs) are subject to the exact same per-election contribution limits as individual donors ($6,400 per election cycle). Only affiliated political party committees are exempt from this limit.', 'https://www.ncsbe.gov/campaign-finance/contribution-limits', 'North Carolina State Board of Elections – Contribution Limits', '2026-05-10', 'per_cycle', 'official_source_direct', 'Applies to PACs donating to state and local campaigns.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('43852c89ae85e6b7', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'When do I have to officially appoint a campaign treasurer?', '["Do I need a treasurer before I raise money?","Filing the treasurer appointment form","When does a campaign legally begin?"]', 'A candidate must appoint a treasurer and file the Organizational Report with the Board of Elections within 10 days of either receiving a contribution, making an expenditure, or officially filing a notice of candidacy—whichever happens first.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-278.7.html', 'N.C.G.S. § 163-278.7(a)', '2026-05-10', 'static', 'statute_citation', 'Applies to all candidates.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('6f3069e26779be0f', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Does my campaign bank account have to be at a North Carolina bank?', '["Campaign depository rules","Can I use an out-of-state bank?","Where can I open my campaign account?"]', 'Yes. All campaign funds must be deposited into a campaign depository that is a bank or credit union authorized to do business in North Carolina.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-278.8.html', 'N.C.G.S. § 163-278.8(f)', '2026-05-10', 'static', 'statute_citation', 'Applies to all campaign treasurers.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('31bae26845389e56', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'How far from the polling place entrance must campaign volunteers stay?', '["Electioneering distance rules","Where can we hold signs at the polls?","Buffer zone restrictions"]', 'North Carolina enforces a 50-foot buffer zone from the entrance of the polling place, within which electioneering is prohibited. County boards may reduce this to no less than 25 feet only if the full 50-foot zone is physically impossible to enforce.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-166.4.html', 'N.C.G.S. § 163-166.4(a)', '2026-05-10', 'static', 'statute_citation', 'Applies to all campaign volunteers and electioneers.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('84fc40fd0937b57d', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Does a mail-in absentee ballot require a witness signature in North Carolina?', '["Do I need a notary for my mail ballot?","Witness requirements for absentee voting","Who can sign the ballot envelope?"]', 'Yes. North Carolina law requires that an absentee ballot envelope be signed by the voter in the presence of two witnesses who must also sign the envelope, OR it must be signed in the presence of a notary public.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-231.html', 'N.C.G.S. § 163-231(a)', '2026-05-10', 'static', 'statute_citation', 'Applies to all voters casting absentee-by-mail ballots.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('2376898b420c5a0d', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Is photo ID required to vote in person, and what if a voter doesn''t have one?', '["Voter ID rules","Voting without an ID","ID Exception process"]', 'Yes, voters must show an acceptable photo ID. If a voter lacks one, they may complete a Photo ID Exception Form at the polls declaring a ''reasonable impediment'' and cast a provisional ballot, which is counted if the county board verifies the form is properly completed.', 'https://www.ncsbe.gov/voting/voter-id', 'North Carolina State Board of Elections – Voter ID', '2026-05-10', 'static', 'official_source_direct', 'Applies to all in-person voters.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('47c15c54a5a81ec6', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Can a voter register on Election Day?', '["Same-day registration rules","Registering at the polls","Is it too late to register on election day?"]', 'No. Same-day voter registration is NOT permitted on Election Day. However, same-day registration is legally permitted during the early voting (One-Stop) period prior to Election Day.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-82.6B.html', 'N.C.G.S. § 163-82.6B', '2026-05-10', 'static', 'statute_citation', 'Applies to unregistered eligible voters.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('c1eaf8ac6949ae9f', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'How long is the early voting (One-Stop) period?', '["When does early voting start?","One-stop voting dates","Duration of early voting window"]', 'In North Carolina, the early voting period (known as One-Stop absentee voting) begins on the third Thursday before an election and ends at 3:00 p.m. on the last Saturday before the election.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-227.2.html', 'N.C.G.S. § 163-227.2(b)', '2026-05-10', 'static', 'statute_citation', 'Applies to all elections offering early voting.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('3f774737a5f35205', 'NC', '["federal"]', 'ballot_access', 'What is the specific filing fee to run for U.S. Senate or U.S. House in North Carolina?', '["How much to run for Congress?","Congressional filing fee","Federal qualifying fee amount"]', 'Based on the statutory formula of 1% of the annual salary of the office, the filing fee for a candidate for U.S. House or U.S. Senate in North Carolina is $1,740.00 (1% of the $174,000 federal salary).', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-107.html', 'N.C.G.S. § 163-107(a)', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to candidates for U.S. Congress.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('7255ae1c00a6b88f', 'NC', '["state"]', 'ballot_access', 'What is the specific filing fee to run for the North Carolina State Senate or State House?', '["How much to run for state legislature?","State rep qualifying fee","Cost to get on the ballot for General Assembly"]', 'The filing fee is 1% of the base annual salary. Because per diem and expense allowances are excluded, the fee is based strictly on the $13,951 base salary, resulting in a statutory qualifying fee of $139.51.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-107.html', 'N.C.G.S. § 163-107(a)', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to candidates for the North Carolina General Assembly.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('0356e8ac079722a9', 'NC', '["judicial"]', 'ballot_access', 'What is the filing fee for an Appellate or Supreme Court Justice?', '["How much to run for state supreme court?","Appellate judge filing fee","Cost to run for higher courts"]', 'The fee is 1% of the annual salary. Based on recent budgets, a Supreme Court Associate Justice fee is $1,757.25 (salary $175,725), and a Court of Appeals Judge fee is $1,692.65 (salary $169,265).', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-107.html', 'N.C.G.S. § 163-107(a)', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to candidates for North Carolina appellate courts.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('bd85942edcbd6d42', 'NC', '["judicial"]', 'ballot_access', 'What is the filing fee for a Superior Court Judge?', '["How much to run for superior court?","Trial judge filing fee","Cost for district court judge"]', 'The fee is 1% of the annual salary. For a Superior Court Judge (base salary ~$162,204), the qualifying filing fee is approximately $1,622.04.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-107.html', 'N.C.G.S. § 163-107(a)', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to candidates for Superior Court.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('cfc738d7380bfd8d', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'What is the standard voter registration deadline for a primary or general election?', '["When do the voter registration books close?","Registration cutoff date","Last day to register to vote"]', 'The standard deadline to register to vote (or update party affiliation) by mail or online is 25 days before the date of the election.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-82.6.html', 'N.C.G.S. § 163-82.6(d)', '2026-05-10', 'static', 'statute_citation', 'Applies to all unregistered eligible voters.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('114850d09ef3ac51', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What documents does a voter need to use Same-Day Registration during early voting?', '["Proof of residency for same day registration","How to register at the polls","One-stop registration requirements"]', 'To use same-day registration during One-Stop early voting, an individual must provide a valid photo ID AND proof of residency, such as a current utility bill, bank statement, paycheck, or government document showing their name and current address.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-82.6B.html', 'N.C.G.S. § 163-82.6B(b)', '2026-05-10', 'static', 'statute_citation', 'Applies to voters registering during the early voting period.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('63c5422ef7a5750a', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What are the required hours for One-Stop Early Voting locations?', '["When are early voting polls open?","Weekend early voting rules","Uniform hours for one-stop"]', 'On weekdays (Monday through Friday), all early voting sites must be open uniformly from 8:00 a.m. to 7:30 p.m. If a county chooses to open sites on weekends, the weekend hours must be uniform across all sites, but are not forced to be 8:00 to 7:30.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-227.6.html', 'N.C.G.S. § 163-227.6(c)', '2026-05-10', 'static', 'statute_citation', 'Applies to election administrators and campaign GOTV efforts.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('629644b1981a8380', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'When is the deadline to request an absentee ballot by mail?', '["Last day to ask for a mail ballot","Cutoff to request absentee","Mail ballot request deadline"]', 'A voter must submit a formal request for an absentee ballot by 5:00 p.m. on the Tuesday before Election Day.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-230.1.html', 'N.C.G.S. § 163-230.1(a)', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to voters requiring absentee-by-mail ballots.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('9de8b7782c38705c', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Does a mail-in absentee ballot have a postmark grace period if it arrives after Election Day?', '["Absentee return deadline","How late can an absentee ballot arrive?","SB 747 mail ballot rules"]', 'No. Under the 2023 SB 747 election reforms, the 3-day postmark grace period was eliminated. All civilian absentee-by-mail ballots MUST be physically received by the county board of elections by 7:30 p.m. on Election Day to be counted.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-231.html', 'N.C.G.S. § 163-231(b)(1)', '2026-05-10', 'static', 'statute_citation', 'Applies to domestic civilian voters returning mail ballots.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('06ce9a61ac46e08d', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'When are provisional ballots researched and counted?', '["Provisional ballot timeline","When do provisional votes get added?","County canvass process"]', 'Provisional ballots are researched and evaluated for eligibility by the county board of elections during the 10-day canvass period following Election Day. Approved provisional ballots are added to the final official totals at the canvass meeting.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-166.11.html', 'N.C.G.S. § 163-166.11(5)', '2026-05-10', 'static', 'statute_citation', 'Applies to post-election tabulation.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('d02e3948c61a63c5', 'NC', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What is the campaign finance reporting schedule during an election year?', '["How often do I file finance reports?","Even year reporting schedule","When are my disclosure reports due?"]', 'In an election year, candidates must file a First Quarter report, a Second Quarter report, a Third Quarter report, and a Fourth Quarter report. They must also file specialized pre-primary and pre-election reports depending on the specific date of the ballot.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-278.9.html', 'N.C.G.S. § 163-278.9', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates active in the current election year.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('be568df290a58c0f', 'NC', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What is the penalty for filing a campaign finance report late?', '["How much are late fees for ethics reports?","Fines for missing a deadline","State Board penalties"]', 'The State Board of Elections assesses a late fee of $50 per day for non-statewide candidates (up to a maximum of $500). For statewide candidates, the penalty is $250 per day, up to a maximum of $10,000.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-278.34.html', 'N.C.G.S. § 163-278.34(a)', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to all candidates failing to file disclosure reports on time.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('3418998e97fb652e', 'NC', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can I use campaign funds to pay my personal mortgage or buy groceries?', '["Personal use of campaign funds","Can I pay rent with donor money?","Impermissible uses of campaign cash"]', 'No. North Carolina law strictly dictates that campaign funds shall not be used for personal purposes. Funds may only be used for expenditures resulting from the campaign for public office or expenses associated with holding that office.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-278.16B.html', 'N.C.G.S. § 163-278.16B(a)', '2026-05-10', 'static', 'statute_citation', 'Applies to all candidates and officeholders.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('1e6f7f5913cec306', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What legally constitutes an ''Independent Expenditure'' in North Carolina?', '["Definition of independent expenditure","PAC spending rules","What makes an expenditure independent?"]', 'An independent expenditure is an expenditure made to support or oppose a candidate that is made entirely without consultation, coordination, or cooperation with the candidate or the candidate''s campaign committee.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-278.14C.html', 'N.C.G.S. § 163-278.14C', '2026-05-10', 'static', 'statute_citation', 'Applies to third parties and PACs making political expenditures.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('c0f1950b660aa81b', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'If a PAC discusses an advertisement with my campaign, how is the expenditure classified?', '["Coordinated ad rules","Does a coordinated PAC ad count as a donation?","Reporting shared expenses"]', 'If an expenditure is coordinated with the candidate, it ceases to be independent. It is legally classified as an ''in-kind'' contribution to the campaign, must be reported as such, and counts directly against the donor''s contribution limits.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-278.14C.html', 'N.C.G.S. § 163-278.14C', '2026-05-10', 'static', 'statute_citation', 'Applies to campaigns interacting with outside groups.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('92ca54cd5471fd0a', 'NC', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Are political party committees subject to the $6,400 contribution limit?', '["Party committee contribution limits","Can the GOP give me unlimited money?","State party funding rules"]', 'No. Under North Carolina law, official political party executive committees (state, district, or county) are entirely exempt from the per-election contribution limits. They may contribute unlimited amounts to their party''s candidates.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-278.13.html', 'N.C.G.S. § 163-278.13(a)', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates receiving formal political party support.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('3df7fe93e40cda9f', 'NC', '["state","judicial"]', 'finance_ethics', 'When is the Statement of Economic Interest (SEI) due for state candidates?', '["SEI deadline","When do I file financial disclosures?","Ethics paperwork timing"]', 'Candidates for covered state and judicial offices must file their Statement of Economic Interest within 10 days of filing their Notice of Candidacy, or by April 15 of the election year, whichever occurs first.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_138A/GS_138A-22.html', 'N.C.G.S. § 138A-22(a)', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates for covered state and judicial offices.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('5c1c4ddfb881e9b0', 'NC', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'How and when can I legally challenge an opponent''s eligibility to run for office?', '["Candidacy challenge procedure","Proving my opponent doesn''t live in the district","Filing a protest against a candidate"]', 'A registered voter of the district may challenge a candidate''s qualifications (like residency) by filing a formal written petition with the county board of elections within 10 business days after the close of the candidate filing period.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-127.2.html', 'N.C.G.S. § 163-127.2', '2026-05-10', 'static', 'statute_citation', 'Applies to individuals initiating eligibility disputes against candidates.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('03a5a55f1f6294e0', 'NC', '["state"]', 'ballot_access', 'How many petition signatures does an unaffiliated candidate need to run for statewide office?', '["Independent candidate petition rules","Signatures to run for statewide office","Avoiding the party primary"]', 'An unaffiliated candidate for statewide office must submit a petition signed by qualified voters equal in number to 1.5% of the total number of registered voters in the state as of January 1 of the election year.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-122.html', 'N.C.G.S. § 163-122(a)(1)', '2026-05-10', 'static', 'statute_citation', 'Applies to unaffiliated candidates for statewide positions.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('880c192e1f619f1e', 'NC', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'Does North Carolina have a ''Sore Loser'' law preventing me from running as an independent if I lose the primary?', '["Can a primary loser run in the general?","Running as unaffiliated after losing","Sore loser prohibitions"]', 'Yes. A candidate who was defeated in a political party primary is legally prohibited from running for the same office as an unaffiliated candidate in the succeeding general election.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-122.html', 'N.C.G.S. § 163-122(a)', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates defeated in a partisan primary.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('8526b6f3e8c2d5c4', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'ballot_access', 'Does my Notice of Candidacy form need to be notarized?', '["Notarizing the filing form","Who can swear in my candidate app?","Do I need a notary for my paperwork?"]', 'Yes. The Notice of Candidacy must be signed in the presence of the election board official receiving it, or it must be acknowledged and certified by a notary public.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-106.html', 'N.C.G.S. § 163-106(a)', '2026-05-10', 'static', 'statute_citation', 'Applies to all candidates filing for office.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('365a2dc2e46cb5f2', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'ballot_access', 'What happens if I want to withdraw my candidacy after I qualify?', '["How do I quit the race?","Removing my name from the ballot","Withdrawal procedures and refunds"]', 'A candidate may withdraw their Notice of Candidacy and receive a refund of their filing fee ONLY if they submit a written notice of withdrawal prior to the close of the candidate filing period. After the deadline, the name remains on the ballot and the fee is forfeited.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-106.4.html', 'N.C.G.S. § 163-106.4', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates wishing to officially terminate their campaign.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('fb1a2fe266091529', 'NC', '["state"]', 'election_dates', 'Is the Governor of North Carolina on the ballot in 2026?', '["2026 gubernatorial race","What state offices are up in 2026?","Is there a race for governor this cycle?"]', 'No. The Governor of North Carolina serves a four-year term and was last elected in 2024. The next gubernatorial election will be in 2028.', 'https://www.ncsbe.gov/voting/upcoming-election', 'North Carolina State Board of Elections – Upcoming Election', '2026-05-10', 'static', 'official_source_direct', 'Applies to candidate and voter awareness of the 2026 cycle.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('a5f1dee44ed83f83', 'NC', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'What is the procedure for running as a write-in candidate?', '["How do I register as a write-in?","Do write-in votes automatically count?","Petition requirement for write-ins"]', 'To have write-in votes officially counted, a candidate must submit a petition (e.g., 500 signatures for statewide office, 100 for district/county office) and a declaration of intent to the Board of Elections at least 90 days before the general election.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-123.html', 'N.C.G.S. § 163-123', '2026-05-10', 'static', 'statute_citation', 'Applies to all individuals seeking official write-in status.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('cd03353f633b2c73', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What are the basic voter eligibility requirements in North Carolina?', '["Who can register to vote?","Voting age and citizenship","Can out of state college students vote?"]', 'To vote in North Carolina, an individual must be a U.S. citizen, at least 18 years old (or 18 by the date of the general election), and a resident of North Carolina and the specific precinct for 30 days next preceding an election.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-55.html', 'N.C.G.S. § 163-55(a)', '2026-05-10', 'static', 'statute_citation', 'Applies to all individuals seeking to register to vote.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('025d88e2b4f98a04', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Can an individual with a felony conviction vote in North Carolina?', '["Felony voting rights","Can felons on probation vote?","Restoration of rights in NC"]', 'Voting rights are NOT automatically restored upon release from prison. Under current North Carolina law, an individual with a felony conviction may only register and vote AFTER fully completing their entire sentence, which explicitly includes any period of probation, parole, or post-release supervision.', 'https://www.ncsbe.gov/registering/who-can-register/registering-person-justice-system', 'North Carolina State Board of Elections – Registering as a Person in the Justice System', '2026-05-10', 'static', 'official_source_direct', 'Applies to North Carolina residents with past felony convictions.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('64c5ece1a6d45fcf', 'NC', '["federal"]', 'residency', 'What are the residency and age requirements to run for U.S. Senate or U.S. House?', '["Federal residency rules","Can I run for Congress if I don''t live in the district?","US Senate eligibility"]', 'U.S. Senators must be 30 years old and a citizen for 9 years. U.S. House members must be 25 years old and a citizen for 7 years. For both, the U.S. Constitution only requires the candidate to be an inhabitant of the state when elected; there is no legal requirement to live within the specific congressional district.', 'https://www.ncsbe.gov/candidates/general-candidate-requirements', 'North Carolina State Board of Elections – Candidate Requirements', '2026-05-10', 'static', 'official_source_direct', 'Applies to candidates for the United States Congress.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('a5f9f8e6ce6275cc', 'NC', '["state"]', 'residency', 'What are the residency and age requirements to run for the North Carolina State Senate?', '["How old to run for state senate?","Residency rules for NC senate","District residency timeline"]', 'A candidate for the North Carolina State Senate must be at least 25 years old, a qualified voter of the state, a citizen of North Carolina for at least two years, and a resident of the district they intend to represent for at least one year immediately preceding the election.', 'https://www.ncleg.gov/Laws/Constitution/Article2', 'North Carolina Constitution, Article II, Section 6', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates for the North Carolina Senate.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('9ed528fbef1a0639', 'NC', '["state"]', 'residency', 'What are the residency and age requirements to run for the North Carolina State House?', '["How old to run for state house?","Residency rules for NC house","Do I need to be a citizen of NC for 2 years for the House?"]', 'A candidate for the North Carolina State House must be a qualified voter of the state, at least 21 years old, and a resident of the district they intend to represent for at least one year immediately preceding the election.', 'https://www.ncleg.gov/Laws/Constitution/Article2', 'North Carolina Constitution, Article II, Section 7', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates for the North Carolina House of Representatives.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('963a86d6406758eb', 'NC', '["state","county","municipal","judicial","special_district"]', 'recall_rules', 'Can an elected official be recalled from office in North Carolina?', '["How do we recall a governor?","Statewide recall elections","Removing an official early"]', 'North Carolina has NO statewide recall mechanism for state-level or county-level officials. Recall is only permitted for local officials in a very small number of municipalities (approximately 25 out of 500+) whose local charters specifically grant that power.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_160A/GS_160A-11.html', 'N.C.G.S. § 160A (Context)', '2026-05-10', 'static', 'statute_citation', 'Applies to voters inquiring about recalling elected officials.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('499936c54d9ef1f1', 'NC', '["state","judicial"]', 'finance_ethics', 'What specific financial information must be disclosed on the Statement of Economic Interest (SEI)?', '["What is on the SEI?","Do I have to disclose my debts?","Reporting real estate on ethics forms"]', 'Candidates must disclose real estate holdings over $10,000, vested trusts, non-publicly traded business interests, sources of income exceeding $5,000, and liabilities/debts over $10,000 (excluding standard mortgages and vehicle loans).', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_138A/GS_138A-24.html', 'N.C.G.S. § 138A-24(a)', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates filing a Statement of Economic Interest.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('0b91d4ed0272da9d', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Are campaign signs allowed to be placed on state highway rights-of-way?', '["Can I put signs in the median?","Highway campaign sign rules","Does the DOT take down political signs?"]', 'Yes. Unlike most states, North Carolina explicitly permits political signs in the right-of-way of the state highway system during the period beginning 30 days before the start of one-stop early voting and ending 10 days after the primary or election, provided they do not obscure motorist visibility.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_136/GS_136-32.html', 'N.C.G.S. § 136-32(b)', '2026-05-10', 'static', 'statute_citation', 'Applies to all campaigns placing signage.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('4982ca4ea7e501e0', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What is the deadline to remove campaign signs after an election?', '["When do I have to take down my yard signs?","Post-election signage removal","How long can signs stay up?"]', 'State law dictates that any political sign placed in the public right-of-way must be removed no later than 10 days after the primary or election day. Signs on private property are governed by local ordinances.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_136/GS_136-32.html', 'N.C.G.S. § 136-32(b)', '2026-05-10', 'static', 'statute_citation', 'Applies to all campaigns conducting field operations.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('9bb3f890342eb3d0', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What happens if a voter goes to the wrong precinct on Election Day?', '["Out of precinct voting","Voting at the wrong polling place","Will a provisional ballot count if I''m at the wrong church?"]', 'Yes. Under laws implemented in 2023 (SB 747) and upheld by the courts, a voter must cast their ballot in their assigned precinct on Election Day. Out-of-precinct provisional ballots are entirely rejected and will not count, even for statewide races.', 'https://www.ncsbe.gov/voting/provisional-voting', 'North Carolina State Board of Elections – Provisional Voting', '2026-05-10', 'static', 'official_source_direct', 'Applies to Election Day voters.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('df48e8d9d85c9e33', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What are the disclaimer rules for campaign robocalls?', '["Robocall rules","Voice call political advertising","Do auto-dialers need to say who paid for it?"]', 'Under North Carolina law, any automated political call (robocall) must explicitly include a disclosure stating who paid for the communication and whether it was authorized by a candidate.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-278.39A.html', 'N.C.G.S. § 163-278.39A', '2026-05-10', 'static', 'statute_citation', 'Applies to all campaigns conducting phone outreach.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('80f63d305e4e99b9', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Do SMS text messages sent to voters require a political disclaimer?', '["Text messaging campaign rules","Do campaign texts need disclaimers?","Mass texting disclosure"]', 'Yes. Campaign text messages fall under North Carolina''s general print and media advertising disclosure statutes and must include a ''Paid for by'' sponsorship legend, either directly in the text or via a clear link.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-278.39.html', 'N.C.G.S. § 163-278.39', '2026-05-10', 'static', 'statute_citation', 'Applies to all campaigns using mass SMS.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('75e2337019702f2b', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'How do I value an in-kind contribution?', '["In-kind valuation","How much is a donated venue worth?","Reporting free services"]', 'In-kind contributions must be reported at the fair market value of the good or service at the time it was provided. They are simultaneously reported as both a contribution and an expenditure on the campaign finance report.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-278.6.html', 'N.C.G.S. § 163-278.6(13)', '2026-05-10', 'static', 'statute_citation', 'Applies to all campaigns accepting non-monetary donations.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('f36e55b373b4f714', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'When does a group of people become a ''Political Committee'' requiring registration?', '["Registering a PAC","When do independent groups have to disclose?","Threshold for third-party reporting"]', 'In North Carolina, two or more individuals or entities become a Political Committee and must register with the State Board of Elections once they accept contributions or make expenditures exceeding $100 in a calendar year to support or oppose a candidate.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-278.6.html', 'N.C.G.S. § 163-278.6(74)', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to groups organizing political expenditures.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('98275864f43c422c', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What is the exact ''Paid for by'' disclaimer required on print advertising?', '["What does my yard sign have to say on it?","Pol Adv disclaimer wording","Campaign sign disclosure rules"]', 'All print media must explicitly state ''Paid for by [Name of candidate campaign committee or sponsor].'' If a third party sponsors the ad, it must also state whether it was authorized by a candidate or candidate''s committee.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-278.39.html', 'N.C.G.S. § 163-278.39(a)', '2026-05-10', 'static', 'statute_citation', 'Applies to all candidate political advertising.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('4cee161a58251730', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Are loans to the campaign subject to contribution limits?', '["Can my spouse loan me unlimited money?","Bank loans vs personal loans","Do loans count as donations?"]', 'A candidate or the candidate''s spouse may loan unlimited funds to their own campaign. However, a loan from any other individual or entity is considered a contribution and is strictly subject to the $6,400 per-election limit.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-278.8.html', 'N.C.G.S. § 163-278.8(e)', '2026-05-10', 'static', 'statute_citation', 'Applies to campaigns utilizing loans.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('f52a4d9dbca752ec', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can I get a loan from a commercial bank for my campaign?', '["Commercial bank loans","Are bank loans subject to the contribution limit?","Borrowing from a lending institution"]', 'Yes. A loan made by a commercial lending institution in the regular course of business is not considered a contribution subject to limits, provided it is fully secured or guaranteed.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-278.8.html', 'N.C.G.S. § 163-278.8(e)', '2026-05-10', 'static', 'statute_citation', 'Applies to campaigns acquiring commercial debt.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('a76da96fb410986e', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can two candidates host a joint fundraising event and split the costs?', '["Joint fundraising rules","Sharing campaign event costs","Splitting money with another candidate"]', 'Yes, but they must establish a formal ''Joint Fundraising Committee'' under specific statutory guidelines. The committee must allocate costs and contributions proportionally and issue separate checks to the participating candidate committees.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-278.8A.html', 'N.C.G.S. § 163-278.8A', '2026-05-10', 'static', 'statute_citation', 'Applies to campaigns pooling resources for fundraising.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('6a4991da6f0b4563', 'NC', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Do affiliated PACs have their own separate contribution limits?', '["Connected PAC rules","Can a company make two PACs to double donations?","Affiliated committee limits"]', 'No. Under North Carolina law, all political committees established, financed, maintained, or controlled by the same corporation, labor organization, or person are considered ''affiliated committees'' and share a single $6,400 contribution limit.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-278.13.html', 'N.C.G.S. § 163-278.13(f)', '2026-05-10', 'static', 'statute_citation', 'Applies to multi-PAC organizations and the campaigns receiving their funds.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('1758c29404b400a8', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'ballot_access', 'Do I have to pay to have my unaffiliated petition signatures verified by the county?', '["Cost to verify signatures","Does the Board of Elections charge for petitions?","Petition checking fees"]', 'Yes. Candidates submitting nominating petitions must generally pay the county board of elections 15 cents ($0.15) for each signature checked, unless they file a pauper''s oath indicating inability to pay.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-122.html', 'N.C.G.S. § 163-122(b)', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to unaffiliated candidates using the petition method.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('3edaff2e5d88bfd5', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Can a campaign volunteer help a voter mark their ballot inside the polling place?', '["Voter assistance rules","Who can help someone vote in the booth?","Can I help my mom vote?"]', 'A voter may receive assistance from a near relative. If the voter is blind, disabled, or illiterate, they may request assistance from any person of their choice, EXCEPT an agent of their employer or labor union.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-166.8.html', 'N.C.G.S. § 163-166.8(a)', '2026-05-10', 'static', 'statute_citation', 'Applies to all voters needing assistance and volunteers providing it.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('31b0d552c8eb5a4a', 'NC', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Is there a penalty if I forget to file my Statement of Economic Interest (SEI)?', '["SEI late fees","What if I miss the ethics filing deadline?","Penalty for missing financial disclosure"]', 'Yes. If a candidate fails to file their SEI within 30 days of receiving notice from the State Ethics Commission, they may be assessed a civil penalty of $250, and their name may ultimately be removed from the ballot.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_138A/GS_138A-25.html', 'N.C.G.S. § 138A-25(b)', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates required to file the SEI.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('606e437d0b045bf3', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'ballot_access', 'Can my campaign challenge the validity of an opponent''s petition signatures?', '["Challenging petitions","Throwing out fake signatures","How to dispute an unaffiliated candidate''s ballot access"]', 'Yes. Any qualified voter can challenge the validity of signatures on an unaffiliated candidate''s petition. The county board of elections is legally responsible for verifying that each signatory is a qualified, registered voter of the applicable district.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-122.html', 'N.C.G.S. § 163-122(b)', '2026-05-10', 'static', 'statute_citation', 'Applies to campaigns scrutinizing opponents'' ballot access.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('5dbf2a0941190b7e', 'NC', '["state","county","judicial"]', 'ballot_access', 'Can I pay my filing fee with a personal check?', '["How to pay the filing fee","Do I need a cashier''s check to qualify?","Filing fee payment methods"]', 'No. The filing fee must be paid by a check drafted on the official campaign account, a certified check, a cashier''s check, or a money order. Personal checks are not accepted by the State Board of Elections.', 'https://www.ncsbe.gov/candidates/filing-candidacy', 'North Carolina State Board of Elections – Filing for Candidacy', '2026-05-10', 'static', 'official_source_direct', 'Applies to all candidates paying a qualifying fee.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('fea5ae466844d478', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'If I spend less than $1,000 total on my campaign, do I still have to file quarterly finance reports?', '["Under threshold reporting","Short form campaign finance","Exemption from quarterly reports"]', 'Candidates who do not intend to receive or spend more than $1,000 during the election cycle can file a ''Certification of Threshold'' to be exempt from detailed quarterly reporting, though they must still appoint a treasurer.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-278.10A.html', 'N.C.G.S. § 163-278.10A(a)', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to candidates running low-budget campaigns.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('6d7bc43f468e7ef4', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'What is the voter registration deadline for the March 2026 Primary?', '["When do the voter registration books close for the primary?","Registration cutoff date for March","Last day to register to vote for the 2026 primary"]', 'The deadline to register to vote by mail or online for the March 3, 2026 primary election is Friday, February 6, 2026 (25 days prior to the election).', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-82.6.html', 'N.C.G.S. § 163-82.6(d)', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to unregistered voters seeking to vote in the primary.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('aff53f03338ed712', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'What is the voter registration deadline for the November 2026 General Election?', '["When do the voter registration books close for the general?","Registration cutoff date for November","Last day to register to vote for the 2026 general"]', 'The deadline to register to vote by mail or online for the November 3, 2026 general election is Friday, October 9, 2026 (25 days prior to the election).', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-82.6.html', 'N.C.G.S. § 163-82.6(d)', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to unregistered voters seeking to vote in the general.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('9b354f4ea6bf18d5', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What is the specific 2026 deadline to request a mail-in absentee ballot for the General Election?', '["Last day to ask for a mail ballot in 2026","Cutoff to request absentee for the fall","2026 mail ballot request deadline"]', 'For the 2026 General Election, a voter must submit a formal request for an absentee ballot by 5:00 p.m. on Tuesday, October 27, 2026.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-230.1.html', 'N.C.G.S. § 163-230.1(a)', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to voters requiring absentee-by-mail ballots for the fall election.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('b66b7a382862261c', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What is the specific 2026 deadline to return a mail-in absentee ballot for the General Election?', '["Last day to mail back my ballot in 2026","Cutoff to return absentee for the fall","2026 mail ballot return deadline"]', 'For the 2026 General Election, absentee-by-mail ballots must be physically received by the county board of elections by 7:30 p.m. on Election Day, which is Tuesday, November 3, 2026.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-231.html', 'N.C.G.S. § 163-231(b)(1)', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to voters returning absentee-by-mail ballots for the fall election.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('a97ab9208d223598', 'NC', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'How is the order of candidate names determined on the ballot in North Carolina?', '["Ballot order rules","Do incumbents get listed first?","Is the ballot order randomized?"]', 'The State Board of Elections determines ballot order by a random public drawing of a letter of the alphabet. Candidates whose last names start with that letter appear first, continuing in alphabetical or reverse-alphabetical order as determined by a second drawing.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-165.6.html', 'N.C.G.S. § 163-165.6(c)', '2026-05-10', 'static', 'statute_citation', 'Applies to all candidates appearing on the ballot.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('788c6e6f00e05b0b', 'NC', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can I keep the laptop and printer my campaign bought after the election is over?', '["Keeping campaign equipment","Post-election use of campaign assets","Can I take campaign property home?"]', 'No. Campaign equipment cannot be converted to personal use. If a candidate wishes to keep physical assets purchased by the campaign, they must purchase them from the campaign account at fair market value.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-278.16B.html', 'N.C.G.S. § 163-278.16B(a)', '2026-05-10', 'static', 'statute_citation', 'Applies to campaigns liquidating physical assets.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('33dc29fc52468730', 'NC', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Does North Carolina require candidates to open a separate ''Officeholder Account'' after they win?', '["Officeholder account rules","Do I need a new bank account once elected?","Keeping the campaign account open"]', 'No. North Carolina does not require a separate ''officeholder account.'' An elected official may retain their campaign account and use surplus funds for ordinary and necessary expenses incurred in connection with the holding of public office.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-278.16B.html', 'N.C.G.S. § 163-278.16B(1)', '2026-05-10', 'static', 'statute_citation', 'Applies to successful candidates transitioning to officeholders.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('ea2a0aadeace33d5', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What must I do with my surplus campaign funds after the election?', '["Disposing of leftover money","Can I keep my campaign cash?","Final campaign account closure"]', 'Surplus funds may be returned pro-rata to contributors, donated to a tax-exempt charity, given to a political party, given to the State or local government, or retained in the campaign account for a future election.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-278.16B.html', 'N.C.G.S. § 163-278.16B', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates concluding an election cycle.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('2a32c23e696354b9', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can I transfer leftover funds from my State Senate race to a new campaign for State House?', '["Transferring funds between offices","Rolling over money to a new race","Using senate money for a house run"]', 'Yes. North Carolina law allows you to retain campaign funds and transfer them for use in a future campaign for the same office or a completely different state/local office, provided the transfer complies with state law limits.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-278.16B.html', 'N.C.G.S. § 163-278.16B', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates shifting offices between cycles.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('05469ae3ef68084a', 'NC', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What is a ''bundled'' contribution and how is it reported?', '["Bundling donations","Reporting checks gathered by a fundraiser","Do bundlers count against limits?"]', 'A bundled contribution is when a third party collects multiple checks from individuals and delivers them together. The campaign must report the actual original contributors, not the bundler. Note: Registered lobbyists are strictly prohibited from bundling contributions for legislators.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-278.13C.html', 'N.C.G.S. § 163-278.13C(a)', '2026-05-10', 'static', 'statute_citation', 'Applies to campaigns utilizing fundraisers who gather checks.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('e0cc43853cb37fc1', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'When does an independent expenditure require reporting to the State Board of Elections?', '["IE reporting threshold","When do independent groups have to disclose?","Threshold for third-party reporting"]', 'Any individual or entity making independent expenditures exceeding $100 in an election must report it. During the final push of an election, expenditures over $1,000 trigger a mandatory 48-hour disclosure report.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-278.12.html', 'N.C.G.S. § 163-278.12(a)', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to individuals and groups making political expenditures.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('24a6e20a52ad640c', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'When is the qualifying period for a special election in 2026?', '["Special election dates 2026","When do I file for a vacant seat?","Qualifying for a special election"]', 'There are no fixed, pre-determined qualifying dates for special elections in North Carolina. If a vacancy occurs that requires a special election, the Governor or General Assembly will issue a writ of election specifying the exact filing window and election dates.', 'https://www.ncsbe.gov/voting/upcoming-election', 'North Carolina State Board of Elections – Upcoming Election', '2026-05-10', 'volatile', 'official_source_direct', 'Applies to candidates running for unanticipated vacant offices.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('ecd105a5731cf3ad', 'NC', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can I use campaign funds to pay for legal defense?', '["Paying lawyers with donor money","Are legal fees a campaign expense?","Defending against ethics complaints"]', 'Yes. Campaign funds may be used to pay for attorney''s fees and costs incurred exclusively in connection with the campaign for office, or for defending against civil or criminal actions directly related to the duties of holding office.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-278.16B.html', 'N.C.G.S. § 163-278.16B(2)', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates facing legal or ethics challenges.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('e9a44f63b658d70a', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Does my campaign website or digital ad require a ''Paid for by'' disclaimer?', '["Digital advertising disclaimers","Do Facebook ads need disclosures?","Website paid-for rules"]', 'Yes. Political advertising published in print, broadcast on TV/radio, or distributed via digital advertising platforms (like Facebook, Google, or campaign websites) must include a clear disclosure stating who paid for the communication.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-278.39.html', 'N.C.G.S. § 163-278.39(a)', '2026-05-10', 'static', 'statute_citation', 'Applies to all campaigns running digital advertisements.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('bbdc344e4ffd1160', 'NC', '["state","county","judicial"]', 'ballot_access', 'What happens if a partisan candidate dies or withdraws after the filing deadline?', '["Vacancy after qualifying","Replacing a dead candidate","Nominee replacement procedure"]', 'If a partisan nominee dies, resigns, or is disqualified after the primary but before the general election, the appropriate political party executive committee (state, district, or county level) appoints a replacement nominee to be placed on the ballot.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-114.html', 'N.C.G.S. § 163-114', '2026-05-10', 'static', 'statute_citation', 'Applies to party committees filling a vacancy on the ballot.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('b73c3cd05a837204', 'NC', '["state","county","municipal","judicial"]', 'ballot_access', 'What happens if an unaffiliated candidate withdraws after qualifying?', '["Unaffiliated candidate vacancy","Replacing an independent candidate","Can a new independent jump in if one drops out?"]', 'Unlike partisan candidates who can be replaced by a party committee, if an unaffiliated candidate withdraws, dies, or is disqualified after securing a spot on the ballot, there is no legal mechanism to replace them, and the ballot position remains vacant.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-122.html', 'N.C.G.S. § 163-122 (Context)', '2026-05-10', 'static', 'statute_citation', 'Applies to unaffiliated candidates vacating the ballot.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('571df030709595f5', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can my campaign accept donations from foreign nationals?', '["Accepting money from non-citizens","Foreign contributions in NC","Can someone from overseas donate?"]', 'No. Federal law strictly prohibits foreign nationals from directly or indirectly making contributions or donations of money or other things of value in connection with ANY federal, state, or local election. North Carolina strictly enforces this prohibition.', 'https://www.ncsbe.gov/campaign-finance/contribution-limits', 'North Carolina State Board of Elections – Contribution Limits', '2026-05-10', 'static', 'official_source_direct', 'Applies to all campaigns and political committees.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('c0fc2bc1298d1834', 'NC', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'How do I officially close my campaign account after the election?', '["Ending my campaign reporting obligations","Filing the termination report","How to stop filing ethics reports"]', 'To end reporting obligations, a candidate must file a ''Final Report'' showing a zero balance, no outstanding debts, and confirming that all surplus funds have been properly disposed of under state law.', 'https://www.ncsbe.gov/campaign-finance/reporting-schedules', 'North Carolina State Board of Elections – Reporting Schedules', '2026-05-10', 'static', 'official_source_direct', 'Applies to all candidates wishing to terminate their campaign treasurer appointment.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('02157b4f78c12374', 'NC', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Do PACs file reports on the same schedule as candidates?', '["PAC reporting schedule","When do independent committees file?","Third-party disclosure dates"]', 'Yes. Political Action Committees (PACs) generally follow the same reporting schedule as candidate committees, filing quarterly reports during election years and semi-annual reports during non-election years.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-278.9.html', 'N.C.G.S. § 163-278.9(a)', '2026-05-10', 'static', 'statute_citation', 'Applies to PACs operating in North Carolina.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1'),
  ('6009867524dcad63', 'NC', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Is there a limit on how much of my own money I can loan to my campaign?', '["Can I self-fund my campaign with unlimited loans?","Do personal loans count as donations?","Borrowing money for the campaign"]', 'No. A candidate''s personal funds or personal loans to their own campaign are not subject to the $6,400 individual contribution limit. A candidate may self-fund to an unlimited degree.', 'https://www.ncleg.gov/EnactedLegislation/Statutes/HTML/BySection/Chapter_163/GS_163-278.13.html', 'N.C.G.S. § 163-278.13(d)', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates utilizing self-funding.', 'batch_2026-05-10T17-21-14_north_carolina_full_v1')
